import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';

export default function Register() {
  const [form, setForm] = useState({ username: '', email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const res = await api.post('/auth/register', form);
      login(res.data.token, res.data.user);
      navigate('/');
    } catch (err) {
      setError(err.response?.data?.error || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app-container" style={{ padding: '40px 24px' }}>
      <div style={{
        width: 80, height: 60, background: 'var(--green)',
        borderRadius: 16, margin: '0 auto 24px',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        boxShadow: '0 8px 24px rgba(58,125,44,0.3)'
      }}>
        <span style={{ color: 'white', fontSize: 20, fontWeight: 800 }}>QK</span>
      </div>

      <h1 style={{ textAlign: 'center', fontSize: 24, fontWeight: 800, marginBottom: 24 }}>
        Создать аккаунт
      </h1>

      {error && <div className="error-msg">{error}</div>}

      <form onSubmit={handleSubmit}>
        <div className="input-group">
          <label>Имя</label>
          <input name="username" placeholder="Ваше имя" value={form.username} onChange={handleChange} required />
        </div>
        <div className="input-group">
          <label>Email</label>
          <input name="email" type="email" placeholder="example@email.com" value={form.email} onChange={handleChange} required />
        </div>
        <div className="input-group">
          <label>Пароль</label>
          <input name="password" type="password" placeholder="Минимум 6 символов" value={form.password} onChange={handleChange} required minLength={6} />
        </div>

        <button type="submit" className="btn-primary" disabled={loading}>
          {loading ? 'Создаём аккаунт...' : 'Зарегистрироваться'}
        </button>
      </form>

      <p style={{ textAlign: 'center', marginTop: 20, color: 'var(--text-muted)' }}>
        Уже есть аккаунт?{' '}
        <Link to="/signin" style={{ color: 'var(--green)', fontWeight: 600 }}>Войти</Link>
      </p>
    </div>
  );
}
